import os, glob

out = []

# Check various possible locations
locations = [
    os.path.join(os.getcwd(), 'input'),
    os.path.join(os.getcwd(), 'output'),
    os.getcwd()
]

for loc in locations:
    out.append(f'{loc}:')
    if os.path.exists(loc):
        for f in os.listdir(loc)[:10]:
            size = os.path.getsize(os.path.join(loc, f)) if os.path.isfile(os.path.join(loc, f)) else 0
            if size > 1000000 or 'miner' in f.lower():
                out.append(f'  {f} ({size} bytes)')

result = chr(10).join(out)
